import numpy as np

def select_next_node(cur_truck_pos, depot_pos, all_truck_pos, unvisited_customers):
    if len(unvisited_customers) == 0:
        return None  # No more customers to visit

    def calculate_distance(point1, point2):
        return np.linalg.norm(point1 - point2)

    # Calculate frequency of visits for each unvisited customer amongst all trucks
    visit_counts = {tuple(customer): 0 for customer in unvisited_customers}
    for pos in all_truck_pos:
        closest_customer = min(unvisited_customers, key=lambda x: calculate_distance(x, pos))
        visit_counts[tuple(closest_customer)] += 1

    # Calculate a combined score based on distance and frequency of visits
    scores = []
    for i, customer in enumerate(unvisited_customers):
        visit_fee = visit_counts[tuple(customer)]
        distance = calculate_distance(cur_truck_pos, customer)
        # Lower visit fee and closer distance should yield higher priority (score)
        score = 1 / (1 + distance + visit_fee)
        scores.append(score)

    # Select the customer with the highest score
    best_node = np.argmax(scores)
    return best_node
